const EQ_COLORS = {
  E101: { bg:'#E6F1FB', text:'#0C447C', dot:'#378ADD', row:'#EFF6FD' },
  E102: { bg:'#EAF3DE', text:'#27500A', dot:'#639922', row:'#F2F8EC' },
  E103: { bg:'#FAEEDA', text:'#633806', dot:'#BA7517', row:'#FDF6EA' },
  E104: { bg:'#F3EAFA', text:'#5B2080', dot:'#9B59D0', row:'#F8F3FD' },
  E105: { bg:'#FAEAEA', text:'#7C1F1F', dot:'#CC3333', row:'#FDF3F3' },
};

function getEqColor(equipo) {
  return EQ_COLORS[equipo] || { bg:'#EFEFED', text:'#3A3A3A', dot:'#888', row:'#F8F8F7' };
}

function dateStatus(f) {
  if (!f || f === '') return 'none';
  if (f === 'Cerrada') return 'ok';
  const p = f.replace(/[.]/g, '/').split('/');
  if (p.length < 3) return 'none';
  let [d, m, y] = p;
  if (y.length === 2) y = '20' + y;
  const date = new Date(`${y}-${m.padStart(2,'0')}-${d.padStart(2,'0')}`);
  return date < new Date() ? 'vencida' : 'pendiente';
}

const DATE_COLOR = { vencida:'#A32D2D', pendiente:'#BA7517', ok:'#3B6D11', none:'#9B9893' };

