// ─── ESTADO ──────────────────────────────────────────────────────────────────
const STORAGE_KEY = 'eng_pulling_v3';
const META_KEY    = 'eng_pulling_meta_v2';
let events           = [];
let currentFilter    = 'todos';
let currentCia       = 'todas';
let currentOperacion = 'todas';
let reviewMeta       = { fecha: '', relevador: '', lugar: '' };

function loadState() {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (raw) { events = JSON.parse(raw); } else { events = JSON.parse(JSON.stringify(DEFAULT_EVENTS)); }
    const m = localStorage.getItem(META_KEY);
    if (m) reviewMeta = JSON.parse(m);
  } catch(e) { events = JSON.parse(JSON.stringify(DEFAULT_EVENTS)); }
}

function saveState() {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(events));
    localStorage.setItem(META_KEY, JSON.stringify(reviewMeta));
  } catch(e) {}
}

// ─── ESTADÍSTICAS ────────────────────────────────────────────────────────────
function getStats(evList) {
  evList = evList || events;
  const total = evList.reduce((a,e) => a + e.actions.length, 0);
  const done  = evList.reduce((a,e) => a + e.actions.filter(a => a.done).length, 0);
  const venc  = evList.reduce((a,e) => a + e.actions.filter(a => !a.done && dateStatus(a.fecha)==='vencida').length, 0);
  const pct   = total ? Math.round(done/total*100) : 0;
  return { total, done, pend:total-done, venc, pct };
}

// ─── COMPAÑÍAS ───────────────────────────────────────────────────────────────
function getCias() {
  const s = new Set(events.map(e => e.cia || 'ENG'));
  return ['todas', ...Array.from(s).sort()];
}

function getEquiposByCia(cia) {
  const filtered = cia === 'todas' ? events : events.filter(e => (e.cia||'ENG') === cia);
  return [...new Set(filtered.map(e => e.equipo))].sort();
}

// ─── RENDER PRINCIPAL ────────────────────────────────────────────────────────
function renderAll() {
  // Guardar meta
  reviewMeta.fecha     = document.getElementById('review-date').value || '';
  reviewMeta.relevador = document.getElementById('review-by').value || '';
  reviewMeta.lugar     = document.getElementById('review-lugar') ? document.getElementById('review-lugar').value || '' : '';
  saveState();

  const filtered = getFilteredEvents();
  const st = getStats(filtered);

  document.getElementById('s-total').textContent = st.total;
  document.getElementById('s-done').textContent  = st.done;
  document.getElementById('s-pend').textContent  = st.pend;
  document.getElementById('s-venc').textContent  = st.venc;
  document.getElementById('prog-fill').style.width = st.pct + '%';
  document.getElementById('prog-label').textContent = `${st.done} de ${st.total} acciones completadas`;
  document.getElementById('topbar-pct').textContent  = st.pct + '%';

  renderOperacionTabs();
  renderCiaTabs();
  renderFilterChips();
  renderEvents(filtered);
}

function getFilteredEvents() {
  return events.filter(ev => {
    const ciaOk = currentCia === 'todas' || (ev.cia||'ENG') === currentCia;
    const opOk  = currentOperacion === 'todas' || (ev.operacion||'Pulling') === currentOperacion;
    const eqOk  = currentFilter === 'todos'      ? true
                : currentFilter === 'pendientes'  ? ev.actions.some(a => !a.done)
                : ev.equipo === currentFilter;
    return ciaOk && opOk && eqOk;
  });
}

// ─── TABS DE OPERACIÓN ───────────────────────────────────────────────────────
function renderOperacionTabs() {
  const ops = ['todas', 'Perforación', 'Workover', 'Pulling'];
  const icons = { 'todas':'🔍', 'Perforación':'⛏️', 'Workover':'🔧', 'Pulling':'⚙️' };
  const wrap = document.getElementById('op-tabs');
  if (!wrap) return;
  wrap.innerHTML = ops.map(op => {
    const cnt = op === 'todas' ? events.length : events.filter(e=>(e.operacion||'Pulling')===op).length;
    return `<button class="op-tab${currentOperacion===op?' active':''}" onclick="setOperacion('${op}')">
      ${icons[op]} ${op==='todas'?'Todas':op}
      <span class="op-count">${cnt}</span>
    </button>`;
  }).join('');
}

function setOperacion(op) {
  currentOperacion = op;
  currentFilter = 'todos';
  currentCia = 'todas';
  renderAll();
}

// ─── TABS DE COMPAÑÍA ────────────────────────────────────────────────────────
function renderCiaTabs() {
  const cias = getCias();
  const wrap = document.getElementById('cia-tabs');
  wrap.innerHTML = cias.map(c => {
    const cnt = c === 'todas' ? events.length : events.filter(e=>(e.cia||'ENG')===c).length;
    return `<button class="cia-tab${currentCia===c?' active':''}" onclick="setCia('${c}',this)">
      ${c === 'todas' ? 'Todas las compañías' : c}
      <span class="cia-count">${cnt}</span>
    </button>`;
  }).join('');
}

function setCia(c, btn) {
  currentCia = c;
  currentFilter = 'todos';
  renderAll();
}

// ─── CHIPS DE FILTRO ─────────────────────────────────────────────────────────
function renderFilterChips() {
  const base = getBaseCiaEvents();
  const equipos = [...new Set(base.map(e => e.equipo))].sort();

  const chipsData = [
    { key:'todos', label:'Todos', dot:'#888', count: base.length },
    ...equipos.map(eq => ({
      key: eq,
      label: `${(base.find(e=>e.equipo===eq)?.cia||'ENG')} · ${eq}`,
      dot: getEqColor(eq).dot,
      count: base.filter(e=>e.equipo===eq).length
    })),
    { key:'pendientes', label:'Pendientes', dot:'#A32D2D', count: base.filter(e=>e.actions.some(a=>!a.done)).length },
  ];

  document.getElementById('filters').innerHTML = chipsData.map(c =>
    `<button class="filter-chip${currentFilter===c.key?' active':''}" onclick="setFilter('${c.key}',this)">
      <span class="filter-dot" style="background:${c.dot}"></span>
      ${c.label}
      <span class="filter-count">${c.count}</span>
    </button>`
  ).join('');
}

function getBaseCiaEvents() {
  return currentCia === 'todas' ? events : events.filter(e=>(e.cia||'ENG')===currentCia);
}

function setFilter(f, btn) {
  currentFilter = f;
  renderAll();
}

// ─── RENDER EVENTOS AGRUPADOS POR EQUIPO ────────────────────────────────────
function renderEvents(filtered) {
  const container = document.getElementById('events-container');

  // Agrupar por compañía → equipo
  const groups = {};
  filtered.forEach(ev => {
    const cia = ev.cia || 'ENG';
    const key = `${cia}||${ev.equipo}`;
    if (!groups[key]) groups[key] = { cia, equipo: ev.equipo, events:[] };
    groups[key].events.push(ev);
  });

  const totalEv = filtered.length;
  document.getElementById('section-count').textContent = `${totalEv} evento${totalEv!==1?'s':''}`;

  if (totalEv === 0) {
    container.innerHTML = '<div class="empty"><div class="empty-icon">✓</div><p>No hay eventos para mostrar</p></div>';
    return;
  }

  // Ordenar grupos por cia+equipo
  const sortedGroups = Object.values(groups).sort((a,b)=>(a.cia+a.equipo).localeCompare(b.cia+b.equipo));

  container.innerHTML = sortedGroups.map(g => {
    const eq = getEqColor(g.equipo);
    const gSt = getStats(g.events);
    return `
      <div class="group-header">
        <div class="group-left">
          <span class="group-cia">${g.cia}</span>
          <span class="eq-badge-group" style="background:${eq.bg};color:${eq.text}">${g.equipo}</span>
        </div>
        <div class="group-stats">
          <div class="group-pbar"><div class="group-fill" style="width:${gSt.pct}%;background:${eq.dot}"></div></div>
          <span class="group-count">${gSt.done}/${gSt.total}</span>
        </div>
      </div>
      ${g.events.map(ev => renderCard(ev)).join('')}
    `;
  }).join('');
}

// ─── RENDER TARJETA ──────────────────────────────────────────────────────────
function renderCard(ev) {
  const eq = getEqColor(ev.equipo);
  const done  = ev.actions.filter(a => a.done).length;
  const total = ev.actions.length;
  const pct   = total ? Math.round(done/total*100) : 0;
  const titulo = ev.titulo || ev.desc;

  const imgSrc = IMGS[ev.imgKey] || ev.imgData || '';
  const imgHtml = imgSrc
    ? `<div class="card-img-wrap">
         <img class="card-img" src="${imgSrc}" alt="Foto evento ${ev.id}" loading="lazy"
           onclick="openLightbox('${imgSrc.substring(0,50)}','${ev.id}')" title="Tocar para ampliar">
         <span class="card-img-label">📷 Tocar foto<br>para ampliar</span>
       </div>`
    : '';

  const actionsHtml = ev.actions.length > 0
    ? ev.actions.map(a => {
        const ds = dateStatus(a.fecha);
        const dc = DATE_COLOR[ds];
        const obsId = 'obs-'+ev.id+'-'+a.id;
        return `
          <div class="action-wrap" style="margin-bottom:3px">
            <div class="action-row${a.done?' done':''}" style="background:${a.done?'#F8F8F7':eq.row};margin-bottom:0;border-radius:7px 7px 0 0">
              <div class="cb${a.done?' cb-done':''}" onclick="toggleAction('${ev.id}','${a.id}')">${a.done?'✓':''}</div>
              <div class="action-body" onclick="toggleAction('${ev.id}','${a.id}')">
                <div class="action-desc">${a.desc}</div>
                <div class="action-meta">
                  <span class="action-resp">${a.resp}</span>
                  <span class="action-date" style="color:${dc}">${a.fecha||'Sin fecha'}</span>
                </div>
              </div>
              <button class="btn-del-ac" onclick="deleteAction('${ev.id}','${a.id}',event)" title="Eliminar acción">×</button>
            </div>
            <div class="obs-row" style="background:${a.done?'#F5F5F4':'#FAFAF9'}">
              <textarea class="obs-input" id="${obsId}" placeholder="Observaciones..." onblur="saveObservacion('${ev.id}','${a.id}')">${a.obs||''}</textarea>
            </div>
          </div>`;
      }).join('')
    : '<div style="font-size:12px;color:var(--g400);padding:8px 4px;text-align:center">Sin acciones registradas</div>';

  return `
    <div class="card" id="card-${ev.id}">
      <div class="card-header" onclick="toggleCard('${ev.id}')">
        <div class="card-mid">
          <div class="card-top-row">
            <span class="card-clas" style="color:${eq.text};background:${eq.bg}">${ev.clas}</span>
            <span class="card-id">ID ${ev.id} · ${ev.fecha}</span>
          </div>
          <span class="card-titulo" style="font-size:12px;font-weight:700;color:var(--black);display:block;margin-bottom:2px">${titulo}</span>
          ${ev.titulo ? `<span class="card-desc" style="font-size:11px;color:var(--g600)">${ev.desc}</span>` : ''}
        </div>
        <div class="card-right">
          <div class="mini-pbar"><div class="mini-fill" style="width:${pct}%;background:${eq.dot}"></div></div>
          <span class="card-count">${done}/${total}</span>
          <button class="btn-del-ev" onclick="deleteEvent('${ev.id}',event)" title="Eliminar evento">🗑</button>
          <span class="chevron" id="chev-${ev.id}">›</span>
        </div>
      </div>
      <div class="card-body" id="body-${ev.id}" style="display:none">
        ${imgHtml}
        <div class="actions-list">${actionsHtml}</div>
        <div class="add-ac-inline" id="add-ac-${ev.id}">
          <div class="add-ac-fields" id="add-ac-fields-${ev.id}" style="display:none">
            <input class="add-ac-input" id="add-ac-desc-${ev.id}" type="text" placeholder="Descripción de la acción">
            <div class="add-ac-row">
              <input class="add-ac-input" id="add-ac-resp-${ev.id}" type="text" placeholder="Responsable">
              <input class="add-ac-input" id="add-ac-fecha-${ev.id}" type="text" placeholder="dd/mm/aaaa" style="max-width:110px">
            </div>
            <div class="add-ac-btns">
              <button class="add-ac-cancel" onclick="hideAddAction('${ev.id}')">Cancelar</button>
              <button class="add-ac-save" onclick="saveInlineAction('${ev.id}')">Guardar acción</button>
            </div>
          </div>
          <button class="add-ac-trigger" id="add-ac-btn-${ev.id}" onclick="showAddAction('${ev.id}')">+ Agregar acción correctiva</button>
        </div>
      </div>
    </div>`;
}

// ─── LIGHTBOX ────────────────────────────────────────────────────────────────
function openLightbox(_, evId) {
  const ev = events.find(e => e.id === evId);
  if (!ev) return;
  const src = IMGS[ev.imgKey] || ev.imgData || '';
  if (!src) return;
  const lb = document.getElementById('lightbox');
  document.getElementById('lb-img').src = src;
  lb.style.display = 'flex';
  document.body.style.overflow = 'hidden';
}

function closeLightbox() {
  document.getElementById('lightbox').style.display = 'none';
  document.getElementById('lb-img').src = '';
  document.body.style.overflow = '';
}

// ─── INTERACCIONES ───────────────────────────────────────────────────────────
function toggleCard(id) {
  const body = document.getElementById('body-'+id);
  const chev = document.getElementById('chev-'+id);
  const open = body.style.display === 'block';
  body.style.display = open ? 'none' : 'block';
  chev.style.transform = open ? 'rotate(0deg)' : 'rotate(90deg)';
}

function toggleAction(evId, actionId) {
  const ev = events.find(e => e.id === evId);
  if (!ev) return;
  const ac = ev.actions.find(a => a.id === actionId);
  if (!ac) return;
  ac.done = !ac.done;
  saveState();
  renderAll();
  // Mantener tarjeta abierta
  const body = document.getElementById('body-'+evId);
  if (body) {
    body.style.display = 'block';
    const chev = document.getElementById('chev-'+evId);
    if (chev) chev.style.transform = 'rotate(90deg)';
  }
}

function deleteAction(evId, actionId, e) {
  e.stopPropagation();
  if (!confirm('¿Eliminar esta acción correctiva?')) return;
  const ev = events.find(e => e.id === evId);
  if (!ev) return;
  ev.actions = ev.actions.filter(a => a.id !== actionId);
  saveState();
  renderAll();
  // Mantener tarjeta abierta
  const body = document.getElementById('body-'+evId);
  if (body) {
    body.style.display = 'block';
    const chev = document.getElementById('chev-'+evId);
    if (chev) chev.style.transform = 'rotate(90deg)';
  }
}

function saveObservacion(evId, actionId) {
  const input = document.getElementById('obs-'+evId+'-'+actionId);
  if (!input) return;
  const ev = events.find(e => e.id === evId);
  if (!ev) return;
  const ac = ev.actions.find(a => a.id === actionId);
  if (!ac) return;
  ac.obs = input.value;
  saveState();
  showToast('Observación guardada');
}

function showAddAction(evId) {
  document.getElementById('add-ac-fields-'+evId).style.display = 'block';
  document.getElementById('add-ac-btn-'+evId).style.display   = 'none';
  document.getElementById('add-ac-desc-'+evId).focus();
}

function hideAddAction(evId) {
  document.getElementById('add-ac-fields-'+evId).style.display = 'none';
  document.getElementById('add-ac-btn-'+evId).style.display    = '';
  document.getElementById('add-ac-desc-'+evId).value  = '';
  document.getElementById('add-ac-resp-'+evId).value  = '';
  document.getElementById('add-ac-fecha-'+evId).value = '';
}

function saveInlineAction(evId) {
  const desc  = document.getElementById('add-ac-desc-'+evId).value.trim();
  const resp  = document.getElementById('add-ac-resp-'+evId).value.trim();
  const fecha = document.getElementById('add-ac-fecha-'+evId).value.trim();
  if (!desc) { document.getElementById('add-ac-desc-'+evId).focus(); return; }
  const ev = events.find(e => e.id === evId);
  if (!ev) return;
  const newId = evId + '-' + Date.now();
  ev.actions.push({ id: newId, desc, resp: resp||'—', fecha: fecha||'', done: false });
  saveState();
  renderAll();
  // Mantener tarjeta abierta
  const body = document.getElementById('body-'+evId);
  if (body) {
    body.style.display = 'block';
    const chev = document.getElementById('chev-'+evId);
    if (chev) chev.style.transform = 'rotate(90deg)';
  }
}

function deleteEvent(evId, e) {
  e.stopPropagation();
  const ev = events.find(e => e.id === evId);
  if (!ev) return;
  const titulo = ev.titulo || ev.desc;
  if (!confirm(`¿Eliminar el evento "${titulo}"?\n\nEsta acción no se puede deshacer.`)) return;
  events = events.filter(e => e.id !== evId);
  saveState();
  renderAll();
}

// ─── MODAL NUEVO EVENTO ──────────────────────────────────────────────────────
function openModal() {
  document.getElementById('modal').style.display = 'flex';
  document.getElementById('m-id').value         = '';
  document.getElementById('m-titulo').value     = '';
  document.getElementById('m-fecha').value      = '';
  document.getElementById('m-desc').value       = '';
  document.getElementById('m-cia-new').value    = '';
  document.getElementById('m-equipo-new').value = '';
  document.getElementById('m-operacion').value  = 'Pulling';
  document.getElementById('m-foto-preview').style.display = 'none';
  document.getElementById('m-foto-preview').src = '';
  document.getElementById('m-foto-label').textContent = 'Tocar para agregar foto';
  document.getElementById('m-acciones-list').innerHTML = '';
  window._newEventPhoto = null;
  window._newActions = [];
  renderModalAcciones();
}

function renderModalAcciones() {
  const list = document.getElementById('m-acciones-list');
  if (!window._newActions) window._newActions = [];
  if (window._newActions.length === 0) {
    list.innerHTML = '<div style="font-size:11px;color:var(--g400);padding:4px 0">Sin acciones agregadas aún</div>';
    return;
  }
  list.innerHTML = window._newActions.map((a, i) => `
    <div style="display:flex;align-items:flex-start;gap:8px;padding:7px 8px;background:var(--g50);border-radius:8px;margin-bottom:4px">
      <div style="flex:1">
        <div style="font-size:12px;color:var(--black);line-height:1.4">${a.desc}</div>
        <div style="font-size:11px;color:var(--g400);margin-top:2px">${a.resp||'Sin responsable'} · ${a.fecha||'Sin fecha'}</div>
      </div>
      <button onclick="removeModalAccion(${i})" style="background:none;border:none;cursor:pointer;font-size:16px;color:var(--g300);padding:0;line-height:1">×</button>
    </div>`).join('');
}

function addModalAccion() {
  const desc = document.getElementById('m-ac-desc').value.trim();
  const resp = document.getElementById('m-ac-resp').value.trim();
  const fecha = document.getElementById('m-ac-fecha').value.trim();
  if (!desc) { document.getElementById('m-ac-desc').focus(); return; }
  if (!window._newActions) window._newActions = [];
  window._newActions.push({ desc, resp, fecha });
  document.getElementById('m-ac-desc').value  = '';
  document.getElementById('m-ac-resp').value  = '';
  document.getElementById('m-ac-fecha').value = '';
  renderModalAcciones();
}

function removeModalAccion(i) {
  window._newActions.splice(i, 1);
  renderModalAcciones();
}

function handleFotoInput(input) {
  const file = input.files[0];
  if (!file) return;
  const reader = new FileReader();
  reader.onload = function(e) {
    const preview = document.getElementById('m-foto-preview');
    preview.src = e.target.result;
    preview.style.display = 'block';
    document.getElementById('m-foto-label').textContent = '📷 Foto cargada — tocar para cambiar';
    window._newEventPhoto = e.target.result;
  };
  reader.readAsDataURL(file);
}

function renderEquipoOptions() {
  const sel = document.getElementById('m-equipo');
  const existing = [...new Set(events.map(e => e.equipo))].sort();
  const all = [...new Set([...existing, 'E101','E102','E103'])].sort();
  sel.innerHTML = all.map(eq => {
    const cia = (events.find(e => e.equipo === eq) || {}).cia || 'ENG';
    return `<option value="${eq}">${eq} — ${cia}</option>`;
  }).join('');
}

function closeModal() {
  document.getElementById('modal').style.display = 'none';
}

function saveEvent() {
  const id        = document.getElementById('m-id').value.trim();
  const titulo    = document.getElementById('m-titulo').value.trim();
  const desc      = document.getElementById('m-desc').value.trim();
  const fecha     = document.getElementById('m-fecha').value.trim();
  const cia       = document.getElementById('m-cia-new').value.trim() || 'Sin especificar';
  const equipoNew = document.getElementById('m-equipo-new').value.trim() || 'E-NUEVO';
  const operacion = document.getElementById('m-operacion').value;
  const fotoData  = window._newEventPhoto || null;
  const acciones  = (window._newActions || []).map((a, i) => ({
    id: `${id}-${i}`, desc: a.desc, resp: a.resp||'—', fecha: a.fecha||'', done: false
  }));

  if (!id)    { alert('El ID del evento es obligatorio'); return; }
  if (!titulo){ alert('El título del evento es obligatorio'); return; }
  if (!desc)  { alert('La descripción del evento es obligatoria'); return; }
  if (events.find(e => e.id === id)) { alert('Ya existe un evento con ese ID. Usá uno diferente.'); return; }

  events.push({
    id, imgKey: null, imgData: fotoData,
    equipo: equipoNew, cia, operacion,
    clas: 'FAC', fecha: fecha || '—',
    titulo, desc,
    actions: acciones
  });

  window._newEventPhoto = null;
  window._newActions    = [];
  saveState();
  closeModal();
  renderAll();
  showToast('Evento registrado correctamente');
}

// ─── TOAST ───────────────────────────────────────────────────────────────────
function showToast(msg) {
  const t = document.getElementById('toast');
  t.textContent = msg;
  t.classList.add('show');
  setTimeout(() => t.classList.remove('show'), 2500);
}

// ─── EXPORTAR PDF ────────────────────────────────────────────────────────────
function exportPDF() {
  const fecha     = reviewMeta.fecha     || new Date().toLocaleDateString('es-AR');
  const relevador = reviewMeta.relevador || 'Hermosilla Gastón (SAS CGC)';
  const filtered  = getFilteredEvents();
  const st        = getStats(filtered);

  // Agrupar por cia+equipo
  const groups = {};
  filtered.forEach(ev => {
    const key = `${ev.cia||'ENG'}-${ev.equipo}`;
    if (!groups[key]) groups[key] = { cia:ev.cia||'ENG', equipo:ev.equipo, events:[] };
    groups[key].events.push(ev);
  });

  const rows = Object.values(groups).sort((a,b)=>(a.cia+a.equipo).localeCompare(b.cia+b.equipo)).map(g => {
    const eq = getEqColor(g.equipo);
    const gSt = getStats(g.events);
    const evRows = g.events.map(ev => {
      const actRows = ev.actions.map(a => {
        const dc = DATE_COLOR[dateStatus(a.fecha)];
        return `<tr style="background:${a.done?'#f5f5f5':'#fff'}">
          <td style="padding:4px 7px;font-size:10px;color:${a.done?'#aaa':'#111'};${a.done?'text-decoration:line-through':''}">
            <span style="font-size:9px;color:#999;margin-right:4px">ID ${ev.id}</span>${a.desc}
          </td>
          <td style="padding:4px 7px;font-size:10px;color:#555;white-space:nowrap">${a.resp}</td>
          <td style="padding:4px 7px;font-size:10px;color:${dc};white-space:nowrap">${a.fecha||'Sin fecha'}</td>
          <td style="padding:4px 7px;text-align:center;font-size:11px;color:#1D9E75">${a.done?'✓':''}</td>
        </tr>`;
      }).join('');
      return `<tr>
        <td colspan="4" style="padding:7px 8px;background:#fafafa;border-top:1px solid #e8e8e8">
          <span style="font-size:10px;color:#777;margin-right:6px">${ev.fecha}</span>
          <strong style="font-size:11px">${ev.desc}</strong>
          <span style="float:right;font-size:10px;color:#999">${ev.actions.filter(a=>a.done).length}/${ev.actions.length}</span>
        </td>
      </tr>${evRows}`;
    }).join('');

    const opLabel = g.events[0]?.operacion || 'Pulling';
    return `<tr>
      <td colspan="4" style="padding:9px 10px;background:${eq.bg};border-top:3px solid ${eq.dot}">
        <span style="font-size:11px;font-weight:700;color:${eq.text}">${g.cia} · ${g.equipo}</span>
        <span style="font-size:10px;color:${eq.text};margin-left:8px">${opLabel}</span>
        <span style="float:right;font-size:10px;color:${eq.text}">${gSt.done}/${gSt.total} completadas · ${gSt.pct}%</span>
      </td>
    </tr>${evRows}`;
  }).join('');

  const html = `<!DOCTYPE html><html><head><meta charset="UTF-8">
  <style>
    body{font-family:Arial,sans-serif;margin:0;padding:14px;font-size:11px}
    .hdr{display:flex;align-items:center;gap:10px;border-bottom:3px solid #111;padding-bottom:10px;margin-bottom:12px}
    .logo{background:#111;color:#fff;padding:5px 11px;font-size:15px;font-weight:700;letter-spacing:3px;border-radius:3px}
    .lbar{height:3px;background:#1D9E75;border-radius:2px;margin-top:2px}
    .stats{display:flex;gap:8px;margin-bottom:10px}
    .stat{background:#f8f8f7;padding:7px 10px;border-radius:6px}
    .sl{font-size:9px;color:#999}.sv{font-size:16px;font-weight:700}
    .pbar{height:5px;background:#eee;border-radius:3px;margin-bottom:10px;overflow:hidden}
    .pf{height:5px;background:#1D9E75;border-radius:3px}
    table{width:100%;border-collapse:collapse}
    th{background:#111;color:#fff;padding:5px 7px;text-align:left;font-size:9px;text-transform:uppercase;letter-spacing:.4px}
    td{border-bottom:1px solid #eee;vertical-align:top}
    .footer{margin-top:12px;font-size:9px;color:#999;border-top:1px solid #eee;padding-top:8px}
  </style></head><body>
  <div class="hdr">
    <div><div class="logo">CGC</div><div class="lbar"></div></div>
    <div>
      <div style="font-size:13px;font-weight:700">Reporte de Acciones Correctivas — Operaciones Pulling</div>
      <div style="font-size:10px;color:#666;margin-top:1px">Cuenca Golfo San Jorge · Sep 2025 – Mar 2026</div>
      <div style="font-size:10px;color:#666">Relevado por: ${relevador} · Fecha: ${fecha}</div>
    </div>
  </div>
  <div class="stats">
    <div class="stat"><div class="sl">Total</div><div class="sv">${st.total}</div></div>
    <div class="stat"><div class="sl">Completadas</div><div class="sv" style="color:#1D9E75">${st.done}</div></div>
    <div class="stat"><div class="sl">Pendientes</div><div class="sv" style="color:#BA7517">${st.pend}</div></div>
    <div class="stat"><div class="sl">Avance</div><div class="sv">${st.pct}%</div></div>
  </div>
  <div class="pbar"><div class="pf" style="width:${st.pct}%"></div></div>
  <table>
    <thead><tr><th style="width:50%">Acción</th><th style="width:22%">Responsable</th><th style="width:14%">Fecha</th><th style="width:7%;text-align:center">OK</th></tr></thead>
    <tbody>${rows}</tbody>
  </table>
  <div class="footer">Generado por App ENG Pulling CGC · ${new Date().toLocaleDateString('es-AR',{day:'2-digit',month:'long',year:'numeric'})}</div>
  </body></html>`;

  // Mostrar reporte en pantalla completa dentro de la misma página
  let reportDiv = document.getElementById('report-overlay');
  if (!reportDiv) {
    reportDiv = document.createElement('div');
    reportDiv.id = 'report-overlay';
    reportDiv.style.cssText = 'position:fixed;inset:0;background:#fff;z-index:1000;overflow-y:auto;padding:0';
    document.body.appendChild(reportDiv);
  }
  // Extraer solo el body del HTML
  const bodyStart = html.indexOf('<body>') + 6;
  const bodyEnd   = html.lastIndexOf('</body>');
  const bodyHtml  = bodyStart > 6 && bodyEnd > 0 ? html.slice(bodyStart, bodyEnd) : html;
  reportDiv.innerHTML = '<div style="position:sticky;top:0;background:#111;color:#fff;display:flex;align-items:center;gap:12px;padding:10px 16px;z-index:10">'
    + '<button onclick="closeReport()" style="background:none;border:none;color:#fff;font-size:22px;cursor:pointer;padding:0;line-height:1">←</button>'
    + '<span style="font-size:14px;font-weight:600;flex:1">Reporte de acciones</span>'
    + '<button onclick="window.print()" style="background:#1D9E75;border:none;color:#fff;padding:7px 14px;border-radius:8px;font-size:13px;font-weight:600;cursor:pointer">Imprimir / PDF</button>'
    + '</div>'
    + '<div style="padding:16px;max-width:800px;margin:0 auto">' + bodyHtml + '</div>';
  reportDiv.style.display = 'block';
  document.body.style.overflow = 'hidden';
}

function closeReport() {
  const d = document.getElementById('report-overlay');
  if (d) { d.style.display = 'none'; }
  document.body.style.overflow = '';
}

// ─── EXPORTAR CSV ────────────────────────────────────────────────────────────
function exportCSV() {
  const fecha    = reviewMeta.fecha     || new Date().toISOString().split('T')[0];
  const relev    = reviewMeta.relevador || 'Sin especificar';
  const lugar    = reviewMeta.lugar     || 'Sin especificar';
  const filtered = getFilteredEvents();

  if (typeof XLSX === 'undefined') {
    const s = document.createElement('script');
    s.src = 'https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js';
    s.onload  = () => buildExcelReport(filtered, fecha, relev, lugar);
    s.onerror = () => showToast('Sin conexión — necesitás internet la primera vez');
    document.head.appendChild(s);
  } else {
    buildExcelReport(filtered, fecha, relev, lugar);
  }
}

function buildExcelReport(filtered, fecha, relev, lugar) {
  // ── Paleta ────────────────────────────────────────────────────────────────
  const C = {
    black:'FF111111', white:'FFFFFFFF', teal:'FF1D9E75', tealLt:'FFE1F5EE',
    gray:'FFEFEFED',  grayDk:'FF9B9893', grayMd:'FFDEDCDA',
    red:'FFA32D2D',   redLt:'FFFDEAEA',
    amber:'FFBA7517', amberLt:'FFFDF6EA',
    green:'FF3B6D11', greenLt:'FFEAF3DE',
    blue:'FF0C447C',  blueLt:'FFE6F1FB',
    e101:'FF378ADD',  e102:'FF639922',  e103:'FFBA7517',
  };
  const EQC = {
    E101:{dot:C.e101,lt:C.blueLt,text:C.blue},
    E102:{dot:C.e102,lt:C.greenLt,text:C.green},
    E103:{dot:C.e103,lt:C.amberLt,text:C.amber},
  };
  function eqc(eq) {
    for (const k of Object.keys(EQC)) { if (String(eq).includes(k)) return EQC[k]; }
    return {dot:C.teal,lt:C.tealLt,text:C.black};
  }

  function st(f) {
    if (!f || String(f).trim()==='') return 'none';
    if (String(f).trim()==='Cerrada') return 'ok';
    const p=String(f).replace(/\./g,'/').split('/');
    if (p.length<3) return 'none';
    let [d,m,y]=p; if(y.length===2) y='20'+y;
    try { const dt=new Date(`${y}-${m.padStart(2,'0')}-${d.padStart(2,'0')}`);
          return dt<new Date()?'vencida':'pendiente'; } catch{return 'none';}
  }
  const stLabel = f => ({ok:'Cerrada',vencida:'Vencida',pendiente:'Pendiente',none:'Sin fecha'})[st(f)];

  function cell(v,bg,fg,bold,italic,strike,sz,h,wrap,border){
    const s={};
    if(bg) s.fill={patternType:'solid',fgColor:{rgb:bg.replace('FF','')}};
    s.font={name:'Arial',sz:sz||9,bold:!!bold,italic:!!italic,
            strike:!!strike,color:{rgb:(fg||C.black).replace('FF','')}};
    s.alignment={horizontal:h||'left',vertical:'center',wrapText:!!wrap};
    if(border) s.border={
      top:{style:'thin',color:{rgb:'BBBBBB'}},
      bottom:{style:'thin',color:{rgb:'BBBBBB'}},
      left:{style:'thin',color:{rgb:'BBBBBB'}},
      right:{style:'thin',color:{rgb:'BBBBBB'}}};
    return {v, s};
  }
  function hdr(v,bg,fg){return cell(v,bg||C.black,fg||C.white,true,false,false,9,'center',true,true);}
  function dat(v,bg,fg,bold,h,wrap,strike){return cell(v,bg||C.white,fg||C.black,bold,false,strike,9,h||'left',wrap!==false,true);}
  function title(v,bg,sz){return cell(v,bg||C.teal,C.white,true,false,false,sz||11,'left',false,false);}

  // ── Agrupar eventos ───────────────────────────────────────────────────────
  const groups={};
  filtered.forEach(ev=>{
    const k=(ev.cia||'ENG')+'||'+ev.equipo;
    if(!groups[k]) groups[k]={cia:ev.cia||'ENG',equipo:ev.equipo,
                               operacion:ev.operacion||'Pulling',events:[]};
    groups[k].events.push(ev);
  });

  const totT=filtered.reduce((a,e)=>a+e.actions.length,0);
  const totD=filtered.reduce((a,e)=>a+e.actions.filter(a=>a.done).length,0);
  const totP=totT-totD;
  const totV=filtered.reduce((a,e)=>a+e.actions.filter(a=>!a.done&&st(a.fecha)==='vencida').length,0);
  const totPct=totT?Math.round(totD/totT*100):0;

  const HDRS=['Compañía','Equipo','Operación','ID','Fecha Evento','Título',
              'Descripción','Acción Correctiva','Responsable',
              'Fecha Acción','Estado','Completada','Observaciones'];
  const COL_W=[{wch:14},{wch:10},{wch:12},{wch:8},{wch:12},{wch:24},
               {wch:32},{wch:40},{wch:20},{wch:12},{wch:12},{wch:12},{wch:28}];

  const wb = XLSX.utils.book_new();
  const groupStats=[];

  // ════════════════════════════════════════════════════════════════════════
  // HOJAS POR EQUIPO
  // ════════════════════════════════════════════════════════════════════════
  Object.values(groups).sort((a,b)=>(a.cia+a.equipo).localeCompare(b.cia+b.equipo))
  .forEach(g=>{
    const ec=eqc(g.equipo);
    const rows=[];
    // Fila 1: título
    rows.push([cell(`${g.cia} — ${g.equipo} — ${g.operacion}`,ec.dot,C.white,true,false,false,14,'left',false,false),
               ...Array(12).fill(cell('',ec.dot))]);
    // Fila 2: meta
    rows.push([cell(`Relevado por: ${relev}   |   Lugar: ${lugar}   |   Fecha: ${fecha}`,
                    C.gray,C.grayDk,false,false,false,9,'left',false,false),
               ...Array(12).fill(cell('',C.gray))]);
    // Fila 3: encabezados
    rows.push(HDRS.map(h=>hdr(h)));

    let total=0,done=0,venc=0;
    g.events.forEach(ev=>{
      const titulo=ev.titulo||ev.desc||'';
      const desc=ev.desc||'';
      if(!ev.actions||ev.actions.length===0){
        rows.push([dat(g.cia,C.gray,C.grayDk),dat(g.equipo,C.gray,C.grayDk),
                   dat(g.operacion,C.gray,C.grayDk),dat(ev.id,C.gray,C.grayDk),
                   dat(ev.fecha,C.gray,C.grayDk),dat(titulo,C.gray,C.grayDk),
                   dat(desc,C.gray,C.grayDk),dat('(Sin acciones)',C.gray,C.grayDk),
                   ...Array(5).fill(dat('',C.gray,C.grayDk))]);
        return;
      }
      ev.actions.forEach((ac,ai)=>{
        const s=st(ac.fecha); const isDone=ac.done;
        const isVenc=!isDone&&s==='vencida';
        const bg=isDone?C.gray:(isVenc?C.redLt:(ai%2===0?C.blueLt:C.white));
        const fg=isDone?C.grayDk:(isVenc?C.red:C.black);
        rows.push([
          dat(g.cia,bg,fg),dat(g.equipo,bg,fg),dat(g.operacion,bg,fg),
          dat(ev.id,bg,fg,false,'center'),dat(ev.fecha,bg,fg,false,'center'),
          dat(titulo,bg,fg),dat(desc,bg,fg),
          cell(ac.desc,bg,fg,false,false,isDone,9,'left',true,true),
          dat(ac.resp,bg,fg),dat(ac.fecha||'',bg,fg,false,'center'),
          cell(stLabel(ac.fecha),bg,
               s==='ok'?C.green:(s==='vencida'?C.red:(s==='pendiente'?C.amber:C.grayDk)),
               true,false,false,9,'center',false,true),
          cell(isDone?'SI':'NO',bg,isDone?C.green:C.grayDk,true,false,false,9,'center',false,true),
          dat(ac.obs||'',bg,fg)
        ]);
        total++; if(isDone)done++; if(isVenc)venc++;
      });
    });
    const pend=total-done;
    const pct=total?Math.round(done/total*100):0;
    // Fila total
    const tr=Array(13).fill(cell('',ec.dot,C.white,true,false,false,9,'center',false,true));
    tr[7]=cell('TOTALES',ec.dot,C.white,true,false,false,9,'center',false,true);
    tr[9]=cell(`Total: ${total}`,ec.dot,C.white,true,false,false,9,'center',false,true);
    tr[10]=cell(`✓ ${done} (${pct}%)`,ec.dot,C.white,true,false,false,9,'center',false,true);
    tr[11]=cell(`⏳ ${pend}`,ec.dot,C.white,true,false,false,9,'center',false,true);
    tr[12]=cell(`⚠ ${venc}`,ec.dot,C.white,true,false,false,9,'center',false,true);
    rows.push(tr);

    const ws=XLSX.utils.aoa_to_sheet(rows.map(r=>r.map(c=>c.v)));
    // Aplicar estilos
    rows.forEach((row,ri)=>{
      row.forEach((cellObj,ci)=>{
        const addr=XLSX.utils.encode_cell({r:ri,c:ci});
        if(!ws[addr]) ws[addr]={t:'s',v:''};
        ws[addr].s=cellObj.s;
      });
    });
    ws['!cols']=COL_W;
    ws['!rows']=[{hpt:26},{hpt:14},{hpt:22}];
    ws['!freeze']={xSplit:0,ySplit:3};
    XLSX.utils.book_append_sheet(wb,ws,(g.cia+'_'+g.equipo).substring(0,31));
    groupStats.push({label:`${g.cia}·${g.equipo}`,cia:g.cia,equipo:g.equipo,
                     operacion:g.operacion,total,done,pend,venc,pct,
                     dot:ec.dot,lt:ec.lt,text:ec.text});
  });

  // ════════════════════════════════════════════════════════════════════════
  // HOJA RESUMEN
  // ════════════════════════════════════════════════════════════════════════
  const rowsR=[];
  rowsR.push([cell(`RESUMEN GENERAL — ENG PULLING CGC`,C.teal,C.white,true,false,false,14,'left'),
              ...Array(12).fill(cell('',C.teal))]);
  rowsR.push([cell(`Relevado por: ${relev}   |   Lugar: ${lugar}   |   Fecha: ${fecha}`,
                   C.gray,C.grayDk,false,false,false,9,'left'),
              ...Array(12).fill(cell('',C.gray))]);
  rowsR.push(HDRS.map(h=>hdr(h,C.teal)));

  filtered.forEach(ev=>{
    const titulo=ev.titulo||ev.desc||'';
    ev.actions.forEach((ac,ai)=>{
      const s=st(ac.fecha); const isDone=ac.done;
      const isVenc=!isDone&&s==='vencida';
      const bg=isDone?C.gray:(isVenc?C.redLt:(rowsR.length%2===0?C.blueLt:C.white));
      const fg=isDone?C.grayDk:(isVenc?C.red:C.black);
      rowsR.push([
        dat(ev.cia||'ENG',bg,fg),dat(ev.equipo,bg,fg),dat(ev.operacion||'Pulling',bg,fg),
        dat(ev.id,bg,fg,false,'center'),dat(ev.fecha,bg,fg,false,'center'),
        dat(titulo,bg,fg),dat(ev.desc||'',bg,fg),
        cell(ac.desc,bg,fg,false,false,isDone,9,'left',true,true),
        dat(ac.resp,bg,fg),dat(ac.fecha||'',bg,fg,false,'center'),
        cell(stLabel(ac.fecha),bg,
             s==='ok'?C.green:(s==='vencida'?C.red:(s==='pendiente'?C.amber:C.grayDk)),
             true,false,false,9,'center'),
        cell(isDone?'SI':'NO',bg,isDone?C.green:C.grayDk,true,false,false,9,'center'),
        dat(ac.obs||'',bg,fg)
      ]);
    });
  });
  const wsR=XLSX.utils.aoa_to_sheet(rowsR.map(r=>r.map(c=>c.v)));
  rowsR.forEach((row,ri)=>{
    row.forEach((co,ci)=>{
      const addr=XLSX.utils.encode_cell({r:ri,c:ci});
      if(!wsR[addr]) wsR[addr]={t:'s',v:''};
      wsR[addr].s=co.s;
    });
  });
  wsR['!cols']=COL_W;
  wsR['!rows']=[{hpt:26},{hpt:14},{hpt:22}];
  XLSX.utils.book_append_sheet(wb,wsR,'RESUMEN');

  // ════════════════════════════════════════════════════════════════════════
  // HOJA GRÁFICOS Y ESTADÍSTICAS
  // ════════════════════════════════════════════════════════════════════════
  const rowsG=[];
  const GW=[{wch:22},{wch:14},{wch:14},{wch:14},{wch:14},{wch:14},
            {wch:2},{wch:22},{wch:14},{wch:14},{wch:14},{wch:14},{wch:14}];

  // Título
  rowsG.push([cell('GRÁFICOS Y ESTADÍSTICAS — ENG PULLING CGC',C.teal,C.white,true,false,false,14,'left'),
               ...Array(12).fill(cell('',C.teal))]);
  rowsG.push([cell(`Relevado por: ${relev}   |   Lugar: ${lugar}   |   Fecha: ${fecha}`,
                   C.gray,C.grayDk,false,false,false,9,'left'),
              ...Array(12).fill(cell('',C.gray))]);
  rowsG.push(Array(13).fill(cell('',C.white))); // fila vacía

  // KPIs — fila 4
  const pctColor=totPct>=75?C.green:(totPct>=50?C.amber:C.red);
  const pctBg=totPct>=75?C.greenLt:(totPct>=50?C.amberLt:C.redLt);
  const kpis=[
    ['TOTAL',totT,C.black,C.gray],
    ['COMPLETADAS',totD,C.green,C.greenLt],
    ['PENDIENTES',totP,C.amber,C.amberLt],
    ['VENCIDAS',totV,C.red,C.redLt],
    ['% AVANCE',totPct+'%',pctColor,pctBg],
  ];
  rowsG.push(kpis.map(([l])=>cell(l,C.gray,C.grayDk,true,false,false,8,'center',false,true)));
  rowsG.push(kpis.map(([,v,,bg],i)=>cell(v,bg,kpis[i][2],true,false,false,20,'center',false,true)));
  rowsG.push(Array(13).fill(cell('',C.white)));

  // Tabla avance por equipo — cols A-F
  rowsG.push([cell('📋  AVANCE POR EQUIPO',C.black,C.white,true,false,false,10,'left'),
               ...Array(5).fill(cell('',C.black)),
               cell('',C.white),
               cell('📋  CUMPLIMIENTO POR EQUIPO',C.black,C.white,true,false,false,10,'left'),
               ...Array(5).fill(cell('',C.black))]);

  const avHdrs=['Equipo','Total','Completadas','Pendientes','Vencidas','% Avance'];
  const cuHdrs=['Equipo','Eventos','Acciones','Cerradas','Pendientes','Estado'];
  rowsG.push([
    ...avHdrs.map(h=>hdr(h,C.black)),
    cell('',C.white),
    ...cuHdrs.map(h=>hdr(h,C.black))
  ]);

  // Filas de datos
  const tbl_row_start=rowsG.length;
  groupStats.forEach(g=>{
    const ec=eqc(g.equipo);
    const p=g.pct;
    const pcol=p>=75?C.green:(p>=50?C.amber:C.red);
    const pbg=p>=75?C.greenLt:(p>=50?C.amberLt:C.redLt);
    const estado=p>=80?'✅ Óptimo':(p>=50?'⚠️ En progreso':'🔴 Crítico');
    const ecol=p>=80?C.green:(p>=50?C.amber:C.red);
    const ebg=p>=80?C.greenLt:(p>=50?C.amberLt:C.redLt);
    const nevents=filtered.filter(ev=>ev.equipo===g.equipo&&(ev.cia||'ENG')===g.cia).length;
    rowsG.push([
      cell(`${g.cia}·${g.equipo}`,ec.lt,C.black,true,false,false,10,'center',false,true),
      cell(g.total,C.white,C.black,true,false,false,10,'center',false,true),
      cell(g.done,C.greenLt,C.green,true,false,false,10,'center',false,true),
      cell(g.pend,C.amberLt,C.amber,true,false,false,10,'center',false,true),
      cell(g.venc,C.redLt,C.red,true,false,false,10,'center',false,true),
      cell(p+'%',pbg,pcol,true,false,false,11,'center',false,true),
      cell('',C.white),
      cell(`${g.cia}·${g.equipo}`,ec.lt,C.black,true,false,false,10,'center',false,true),
      cell(nevents,C.white,C.black,false,false,false,10,'center',false,true),
      cell(g.total,C.white,C.black,true,false,false,10,'center',false,true),
      cell(g.done,C.greenLt,C.green,true,false,false,10,'center',false,true),
      cell(g.pend,C.amberLt,C.amber,true,false,false,10,'center',false,true),
      cell(estado,ebg,ecol,true,false,false,10,'center',false,true),
    ]);
  });
  // Fila total
  const tr2=[
    cell('TOTAL',C.tealLt,C.teal,true,false,false,10,'center',false,true),
    cell(totT,C.tealLt,C.teal,true,false,false,10,'center',false,true),
    cell(totD,C.greenLt,C.green,true,false,false,10,'center',false,true),
    cell(totP,C.amberLt,C.amber,true,false,false,10,'center',false,true),
    cell(totV,C.redLt,C.red,true,false,false,10,'center',false,true),
    cell(totPct+'%',pctBg,pctColor,true,false,false,11,'center',false,true),
    cell('',C.white),
    ...Array(6).fill(cell('',C.tealLt)),
  ];
  rowsG.push(tr2);
  rowsG.push(Array(13).fill(cell('',C.white)));

  // Tabla datos para gráficos (oculta, cols A-E)
  const chartDataRow=rowsG.length;
  rowsG.push([hdr('Equipo',C.black),hdr('Completadas',C.black),
              hdr('Pendientes',C.black),hdr('Vencidas',C.black),
              hdr('% Avance',C.black),...Array(8).fill(cell('',C.white))]);
  groupStats.forEach(g=>{
    rowsG.push([
      dat(`${g.cia}·${g.equipo}`,eqc(g.equipo).lt),
      dat(g.done,C.greenLt,C.green,true,'center'),
      dat(g.pend,C.amberLt,C.amber,true,'center'),
      dat(g.venc,C.redLt,C.red,true,'center'),
      dat(g.pct,C.tealLt,C.teal,true,'center'),
      ...Array(8).fill(dat(''))
    ]);
  });
  // Torta
  rowsG.push(Array(13).fill(cell('',C.white)));
  const pieRow=rowsG.length;
  rowsG.push([hdr('Estado',C.black),hdr('Cantidad',C.black),...Array(11).fill(cell('',C.white))]);
  [['Completadas',totD,C.greenLt,C.green],
   ['Pendientes',totP,C.amberLt,C.amber],
   ['Vencidas',totV,C.redLt,C.red]].forEach(([l,v,bg,fg])=>{
    rowsG.push([dat(l,bg,fg,true,'center'),dat(v,bg,fg,true,'center'),
                ...Array(11).fill(cell('',C.white))]);
  });

  const wsG=XLSX.utils.aoa_to_sheet(rowsG.map(r=>r.map(c=>c.v)));
  rowsG.forEach((row,ri)=>{
    row.forEach((co,ci)=>{
      const addr=XLSX.utils.encode_cell({r:ri,c:ci});
      if(!wsG[addr]) wsG[addr]={t:'s',v:typeof co.v==='number'?co.v:''};
      wsG[addr].s=co.s;
      if(typeof co.v==='number') wsG[addr].t='n';
    });
  });
  wsG['!cols']=GW;
  wsG['!rows']=[{hpt:26},{hpt:14},{hpt:8},{hpt:14},{hpt:32}];

  // ── Merges para títulos ───────────────────────────────────────────────────
  wsG['!merges']=[
    {s:{r:0,c:0},e:{r:0,c:12}},
    {s:{r:1,c:0},e:{r:1,c:12}},
    {s:{r:3,c:0},e:{r:3,c:4}},  // KPI labels row
    {s:{r:4,c:0},e:{r:4,c:4}},  // KPI values row
  ];

  XLSX.utils.book_append_sheet(wb,wsG,'GRÁFICOS Y ESTADÍSTICAS');

  // ── Descargar ─────────────────────────────────────────────────────────────
  const fname='ENG_Pulling_'+fecha.replace(/-/g,'')+'.xlsx';
  XLSX.writeFile(wb, fname, {bookType:'xlsx',type:'binary',cellStyles:true});
  showToast('Excel descargado con gráficos y estadísticas');
}


// ─── SERVICE WORKER ───────────────────────────────────────────────────────────
if ('serviceWorker' in navigator) {
  window.addEventListener('load', () => {
    navigator.serviceWorker.register('./sw.js').catch(()=>{});
  });
}

// ─── INIT ─────────────────────────────────────────────────────────────────────
document.addEventListener('DOMContentLoaded', () => {
  loadState();
  document.getElementById('review-date').value = reviewMeta.fecha || new Date().toISOString().split('T')[0];
  document.getElementById('review-by').value   = reviewMeta.relevador || '';
  document.getElementById('review-lugar').value = reviewMeta.lugar || '';
  // guardar meta al cambiar campos
  document.getElementById('review-date').addEventListener('change', () => { reviewMeta.fecha = document.getElementById('review-date').value; saveState(); });
  document.getElementById('review-by').addEventListener('input',   () => { reviewMeta.relevador = document.getElementById('review-by').value; saveState(); });
  document.getElementById('review-lugar').addEventListener('input', () => { reviewMeta.lugar = document.getElementById('review-lugar').value; saveState(); });
  renderAll();
});
